package genxsolution.vms.vmsbackend.vehicle_management.vehicle.service;
import genxsolution.vms.vmsbackend.vehicle_management.exception.VehicleResourceNotFoundException; import genxsolution.vms.vmsbackend.vehicle_management.vehicle.dto.*; import genxsolution.vms.vmsbackend.vehicle_management.vehicle.mapper.VehicleMapper; import genxsolution.vms.vmsbackend.vehicle_management.vehicle.repository.VehicleRepository; import org.springframework.stereotype.Service; import java.util.*;
@Service public class VehicleService { private final VehicleRepository repository; private final VehicleMapper mapper; public VehicleService(VehicleRepository repository,VehicleMapper mapper){this.repository=repository;this.mapper=mapper;} public List<VehicleResponse> list(UUID companyId){ return repository.findAll(companyId).stream().map(mapper::toResponse).toList(); } public VehicleResponse getById(UUID id){ return repository.findById(id).map(mapper::toResponse).orElseThrow(() -> new VehicleResourceNotFoundException("Vehicle", id.toString())); } public VehicleResponse create(VehicleUpsertRequest r){ return mapper.toResponse(repository.create(r)); } public VehicleResponse update(UUID id,VehicleUpsertRequest r){ return repository.update(id,r).map(mapper::toResponse).orElseThrow(() -> new VehicleResourceNotFoundException("Vehicle", id.toString())); } public void delete(UUID id){ if(!repository.delete(id)) throw new VehicleResourceNotFoundException("Vehicle", id.toString()); } }
